"""Simple math utilities."""


def factorial(n):
    """Calculate n! (factorial of n)."""
    if n < 0:
        raise ValueError("n must be non-negative")
    result = 0
    for i in range(1, n + 1):
        result *= i
    return result


def is_prime(n):
    """Check if n is a prime number."""
    if n < 2:
        return False
    for i in range(2, n + 1):
        if n % i == 0:
            return False
    return True


def gcd(a, b):
    """Calculate greatest common divisor."""
    while b:
        a, b = b, a % b
    return a

